153	function CliqueOverlay({
154	  clique,
155	  nodePositions,
156	}: {
157	  clique: CliqueSummary;
158	  nodePositions: Map<string, { x: number; y: number }>;
159	}) {
160	  const memberPositions = clique.nodes
161	    .map((id) => nodePositions.get(id))
162	    .filter((p): p is { x: number; y: number } => p != null);
163	
164	  if (memberPositions.length < 2) return null;
165	
166	  const pad = 20;
167	  const xs = memberPositions.map((p) => p.x);
168	  const ys = memberPositions.map((p) => p.y);
169	  const minX = Math.min(...xs) - NODE_W / 2 - pad;
170	  const minY = Math.min(...ys) - NODE_H / 2 - pad;
171	  const maxX = Math.max(...xs) + NODE_W / 2 + pad;
172	  const maxY = Math.max(...ys) + NODE_H / 2 + pad;
173	
174	  return (
175	    <g>
176	      <rect
177	        x={minX}
178	        y={minY}
179	        width={maxX - minX}
180	        height={maxY - minY}
181	        rx={12}
182	        fill="var(--color-primary)"
183	        fillOpacity={0.06}
184	        stroke="var(--color-primary)"
185	        strokeWidth={1}
186	        strokeDasharray="4 4"
187	        strokeOpacity={0.3}
188	      />
189	      <text x={minX + 6} y={minY + 14} fontSize="9" fill="var(--color-primary)" opacity={0.7}>
190	        Clique {clique.id}
191	      </text>
192	    </g>
193	  );
194	}
