101	          <label style={{ fontSize: "0.85rem" }}>
102	            <span style={labelStyle}>New Probability: {formatProbability(probability)}</span>
103	            <input
104	              type="range"
105	              min={0.01}
106	              max={0.99}
107	              step={0.01}
108	              value={probability}
109	              onChange={(e) => setProbability(Number(e.target.value))}
110	              style={{ width: "100%" }}
111	            />
112	          </label>
113	        </div>
114	
115	        {/* Context conditions */}
116	        <div>
117	          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "var(--space-sm)" }}>
118	            <span style={{ fontSize: "0.85rem", fontWeight: 500 }}>
119	              Conditions (given that...)
120	            </span>
121	            <button
122	              type="button"
123	              onClick={addContext}
124	              disabled={otherMarkets.length === 0}
125	              style={addBtnStyle}
126	            >
