1	import { useState } from "react";
2	import { useCpt, useProbabilityEdit } from "@/lib/query/hooks";
3	import { useSession } from "@/features/session/context";
4	import { formatProbability } from "@/lib/utils/format";
5	import { useDraftEdits } from "@/features/history/useDraftEdits";
6	import type { Market } from "@/lib/api/types";
7	
8	interface CptPanelProps {
9	  market: Market;
10	}
11	
12	interface EditingCell {
13	  entryIndex: number;
14	  outcomeId: string;
15	  probability: number;
16	}
17	
18	export function CptPanel({ market }: CptPanelProps) {
19	  const { session, isConfigured } = useSession();
20	  const { data: cptData, isLoading } = useCpt(market.id);
21	  const mutation = useProbabilityEdit(market.id);
22	  const [editing, setEditing] = useState<EditingCell | null>(null);
23	  const draftEdits = useDraftEdits();
24	
25	  if (isLoading) {
26	    return (
27	      <div style={panelStyle}>
28	        <h3 style={headerStyle}>Conditional Probability Table</h3>
29	        <div style={{ color: "var(--color-text-muted)", fontSize: "0.85rem" }}>Loading CPT...</div>
30	      </div>
31	    );
32	  }
33	
34	  if (!cptData) return null;
35	
36	  const { outcomes, parents, entries } = cptData;
37	  const hasParents = parents.length > 0;
38	
39	  const handleCellClick = (entryIndex: number, outcomeId: string, currentP: number) => {
40	    if (!isConfigured) return;
41	    setEditing({ entryIndex, outcomeId, probability: currentP });
42	  };
43	
44	  const handleSubmit = () => {
45	    if (!editing || !cptData) return;
46	    const entry = entries[editing.entryIndex];
47	    if (!entry) return;
48	
49	    const currentP = entry.marginals[editing.outcomeId] ?? 0;
50	    draftEdits.stageDraft({
51	      entryIndex: editing.entryIndex,
52	      outcomeId: editing.outcomeId,
53	      probability: editing.probability,
54	      context: entry.context,
55	      previousProbability: currentP,
56	    });
57	    setEditing(null);
58	  };
59	
60	  const handleCommitDrafts = () => {
61	    const allDrafts = draftEdits.allDrafts();
62	    for (const draft of allDrafts) {
63	      const entry = entries[draft.entryIndex];
64	      if (!entry) continue;
65	      mutation.mutate({
66	        payload: {
67	          accountId: session.accountId,
68	          variableId: market.variableId,
69	          target: {
70	            kind: "marginal",
71	            outcomeId: draft.outcomeId,
72	            probability: draft.probability,
73	          },
74	          context: draft.context,
75	          idempotencyKey: crypto.randomUUID(),
76	        },
77	        session,
78	      });
79	    }
80	    draftEdits.clearDrafts();
81	  };
82	
83	  const handleCancel = () => setEditing(null);
84	
85	  return (
86	    <div style={panelStyle}>
87	      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "var(--space-sm)" }}>
88	        <h3 style={headerStyle}>Conditional Probability Table</h3>
89	        <span style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
90	          {entries.length} row{entries.length !== 1 ? "s" : ""}
91	          {hasParents && ` \u00B7 ${parents.length} parent${parents.length !== 1 ? "s" : ""}`}
92	        </span>
93	      </div>
94	
95	      {!hasParents && (
96	        <p style={{ fontSize: "0.8rem", color: "var(--color-text-muted)", marginBottom: "var(--space-sm)" }}>
97	          No parent variables — showing marginal probabilities.
98	        </p>
99	      )}
100	
101	      <div style={{ borderRadius: "var(--radius-md)", border: "1px solid var(--color-border)", overflow: "hidden" }}>
102	        <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.8rem" }}>
103	          <thead>
104	            <tr style={{ background: "var(--color-bg-hover)" }}>
105	              {hasParents && <th style={thStyle}>Condition</th>}
106	              {outcomes.map((o) => (
107	                <th key={o.id} style={thStyle}>P({o.name})</th>
108	              ))}
109	            </tr>
110	          </thead>
111	          <tbody>
112	            {entries.map((entry, entryIdx) => (
113	              <tr key={entry.contextKey || "__marginal"} style={{ borderTop: "1px solid var(--color-border)" }}>
114	                {hasParents && (
115	                  <td style={{ ...tdStyle, fontFamily: "var(--font-mono)", fontSize: "0.75rem" }}>
116	                    {entry.context.map((c) => {
117	                      const parent = parents.find((p) => p.variableId === c.variableId);
118	                      const outcomeName = parent?.outcomes.find((o) => o.id === c.outcomeId)?.name ?? c.outcomeId;
119	                      const parentName = parent?.title ?? c.variableId;
120	                      return `${parentName}=${outcomeName}`;
121	                    }).join(", ")}
122	                  </td>
123	                )}
124	                {outcomes.map((o) => {
125	                  const serverP = entry.marginals[o.id] ?? 0;
126	                  const draftP = draftEdits.getDraft(entryIdx, o.id);
127	                  const p = draftP ?? serverP;
128	                  const isDrafted = draftP !== undefined;
129	                  const isEditing = editing?.entryIndex === entryIdx && editing?.outcomeId === o.id;
130	
131	                  if (isEditing) {
132	                    return (
133	                      <td key={o.id} style={tdStyle}>
134	                        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
135	                          <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
136	                            <input
137	                              type="range"
138	                              min={0.01}
139	                              max={0.99}
140	                              step={0.01}
141	                              value={editing.probability}
142	                              onChange={(e) => setEditing({ ...editing, probability: Number(e.target.value) })}
143	                              style={{ flex: 1, minWidth: 60 }}
144	                            />
145	                            <span style={{ fontFamily: "var(--font-mono)", fontSize: "0.75rem", minWidth: 40 }}>
146	                              {formatProbability(editing.probability)}
147	                            </span>
148	                          </div>
149	                          <div style={{ display: "flex", gap: 4 }}>
150	                            <button
151	                              onClick={handleSubmit}
152	                              disabled={mutation.isPending}
153	                              style={setBtnStyle}
154	                            >
155	                              {mutation.isPending ? "..." : "Set"}
156	                            </button>
157	                            <button onClick={handleCancel} style={cancelBtnStyle}>Cancel</button>
158	                          </div>
159	                        </div>
160	                      </td>
161	                    );
162	                  }
163	
164	                  return (
165	                    <td
166	                      key={o.id}
167	                      style={{
168	                        ...tdStyle,
169	                        fontFamily: "var(--font-mono)",
170	                        cursor: isConfigured ? "pointer" : "default",
171	                        position: "relative",
172	                        background: isDrafted ? "rgba(59, 130, 246, 0.06)" : undefined,
173	                      }}
174	                      onClick={() => handleCellClick(entryIdx, o.id, p)}
175	                    >
176	                      <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
177	                        <div style={{
178	                          width: 40,
179	                          height: 6,
180	                          borderRadius: 3,
181	                          background: "var(--color-border)",
182	                          overflow: "hidden",
183	                        }}>
184	                          <div style={{
185	                            width: `${Math.max(2, p * 100)}%`,
186	                            height: "100%",
187	                            borderRadius: 3,
188	                            background: isDrafted ? "var(--color-info)" : p > 0.5 ? "var(--color-success)" : "var(--color-info)",
189	                          }} />
190	                        </div>
191	                        <span>{formatProbability(p)}{isDrafted ? " *" : ""}</span>
192	                      </div>
193	                    </td>
194	                  );
195	                })}
196	              </tr>
197	            ))}
198	          </tbody>
199	        </table>
200	      </div>
201	
202	      {draftEdits.hasDrafts && (
203	        <div style={{ display: "flex", gap: "var(--space-sm)", alignItems: "center", marginTop: "var(--space-sm)" }}>
204	          <button onClick={handleCommitDrafts} disabled={mutation.isPending} style={setBtnStyle}>
205	            {mutation.isPending ? "Submitting…" : `Commit ${draftEdits.allDrafts().length} draft(s)`}
206	          </button>
207	          <button onClick={draftEdits.clearDrafts} style={cancelBtnStyle}>Discard drafts</button>
208	          <span style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
209	            * = drafted (not yet submitted)
210	          </span>
211	        </div>
212	      )}
213	
214	      {mutation.isSuccess && (
215	        <div style={successStyle}>
216	          Edit accepted: {mutation.data.order.orderId}
217	        </div>
218	      )}
219	
220	      {mutation.isError && (
221	        <div style={errorStyle}>
222	          {mutation.error instanceof Error ? mutation.error.message : "Edit failed"}
223	        </div>
224	      )}
225	
226	      {!isConfigured && (
227	        <p style={{ fontSize: "0.75rem", color: "var(--color-text-muted)", marginTop: "var(--space-sm)" }}>
228	          Set your Account ID to edit probabilities.
229	        </p>
230	      )}
231	    </div>
232	  );
233	}
