2	import {
3	  forceSimulation,
4	  forceLink,
5	  forceManyBody,
6	  forceCenter,
7	  forceCollide,
8	  type Simulation,
9	  type SimulationNodeDatum,
10	  type SimulationLinkDatum,
11	} from "d3-force";
12	
13	// ---------------------------------------------------------------------------
14	// Types
15	// ---------------------------------------------------------------------------
16	
17	export interface ForceNode extends SimulationNodeDatum {
18	  id: string;
19	  title: string;
20	  status: string;
21	  /** Pinned position (set by drag) */
22	  fx?: number | null;
23	  fy?: number | null;
24	}
25	
26	export interface ForceLink extends SimulationLinkDatum<ForceNode> {
27	  source: string | ForceNode;
28	  target: string | ForceNode;
29	}
30	
31	export interface ForceGraphPositions {
32	  nodes: Array<{ id: string; x: number; y: number }>;
33	}
34	
35	export interface UseForceGraphOptions {
36	  width: number;
37	  height: number;
38	}
39	
40	// ---------------------------------------------------------------------------
41	// Hook
42	// ---------------------------------------------------------------------------
43	
44	export function useForceGraph(
45	  inputNodes: Array<{ id: string; title: string; status: string }>,
46	  inputLinks: Array<{ source: string; target: string }>,
47	  options: UseForceGraphOptions = { width: 600, height: 400 },
48	) {
49	  const simRef = useRef<Simulation<ForceNode, ForceLink> | null>(null);
50	  const nodesRef = useRef<ForceNode[]>([]);
51	  const linksRef = useRef<ForceLink[]>([]);
52	  const [positions, setPositions] = useState<ForceGraphPositions>({ nodes: [] });
53	
54	  // Stable snapshot updater
55	  const flushPositions = useCallback(() => {
56	    setPositions({
57	      nodes: nodesRef.current.map((n) => ({
58	        id: n.id,
59	        x: n.x ?? 0,
60	        y: n.y ?? 0,
61	      })),
62	    });
63	  }, []);
64	
65	  // Diff and reconcile nodes/links when inputs change
66	  useEffect(() => {
67	    const { width, height } = options;
68	
69	    // --- Diff nodes ---
70	    const prevById = new Map(nodesRef.current.map((n) => [n.id, n]));
71	    const nextNodes: ForceNode[] = inputNodes.map((inp) => {
72	      const existing = prevById.get(inp.id);
73	      if (existing) {
74	        // Preserve position, update data
75	        existing.title = inp.title;
76	        existing.status = inp.status;
77	        return existing;
78	      }
79	      // New node: place near center with jitter
80	      return {
81	        id: inp.id,
82	        title: inp.title,
83	        status: inp.status,
84	        x: width / 2 + (Math.random() - 0.5) * 60,
85	        y: height / 2 + (Math.random() - 0.5) * 60,
86	      };
87	    });
88	
89	    nodesRef.current = nextNodes;
90	
91	    // --- Diff links ---
92	    const nextLinks: ForceLink[] = inputLinks.map((l) => ({
93	      source: l.source,
94	      target: l.target,
95	    }));
96	    linksRef.current = nextLinks;
97	
98	    // --- Create or update simulation ---
99	    if (!simRef.current) {
100	      const sim = forceSimulation<ForceNode>(nextNodes)
101	        .force(
102	          "link",
103	          forceLink<ForceNode, ForceLink>(nextLinks)
104	            .id((d) => d.id)
105	            .distance(120),
106	        )
107	        .force("charge", forceManyBody().strength(-300))
108	        .force("center", forceCenter(width / 2, height / 2))
109	        .force("collide", forceCollide(50))
110	        .on("tick", flushPositions);
111	
112	      simRef.current = sim;
113	    } else {
114	      const sim = simRef.current;
115	      sim.nodes(nextNodes);
116	
117	      const linkForce = sim.force("link") as ReturnType<typeof forceLink<ForceNode, ForceLink>> | undefined;
118	      if (linkForce) {
119	        linkForce.links(nextLinks);
120	      }
121	
122	      // Gentle restart to avoid resetting all positions
123	      sim.alpha(0.1).restart();
124	    }
125	
126	    // Initial flush
127	    flushPositions();
128	  }, [inputNodes, inputLinks, options.width, options.height, flushPositions]);
129	
130	  // Cleanup
131	  useEffect(() => {
132	    return () => {
133	      simRef.current?.stop();
134	    };
135	  }, []);
136	
137	  // Expose simulation ref for drag/zoom integration
138	  const getSimulation = useCallback(() => simRef.current, []);
139	  const getNodes = useCallback(() => nodesRef.current, []);
140	
141	  return {
142	    positions,
143	    getSimulation,
144	    getNodes,
145	    flushPositions,
146	  };
147	}
