3	/** Generic command interface for undo/redo operations */
4	export interface Command {
5	  /** Human-readable description of the action */
6	  readonly description: string;
7	  /** Execute the action */
8	  execute(): void;
9	  /** Reverse the action */
10	  undo(): void;
