1	import { useState, useCallback, useRef } from "react";
2	import type { GraphEdge } from "./deriveEdges";
3	
4	/** Per-hop stagger delay in ms */
5	const HOP_DELAY = 150;
6	/** Maximum total animation duration in ms */
7	const MAX_DURATION = 1500;
8	
9	export interface AnimationState {
10	  /** Set of node IDs currently highlighted by the animation wave */
11	  animatingNodes: Set<string>;
12	  /** Set of edge keys ("source::target" sorted) currently animated */
13	  animatingEdges: Set<string>;
14	  /** The node ID that is the evidence source (glows differently) */
15	  evidenceNodeId: string | null;
16	}
17	
18	function edgeKey(a: string, b: string): string {
19	  return a < b ? `${a}::${b}` : `${b}::${a}`;
20	}
21	
22	/**
23	 * BFS from a starting node along the given edges.
24	 * Returns an array of layers: layer 0 = [startId], layer 1 = its neighbors, etc.
25	 */
26	function bfsLayers(startId: string, edges: GraphEdge[]): string[][] {
27	  const adj = new Map<string, string[]>();
28	  for (const e of edges) {
29	    if (!adj.has(e.source)) adj.set(e.source, []);
30	    if (!adj.has(e.target)) adj.set(e.target, []);
31	    adj.get(e.source)!.push(e.target);
32	    adj.get(e.target)!.push(e.source);
33	  }
34	
35	  const visited = new Set<string>([startId]);
36	  const layers: string[][] = [[startId]];
37	  let frontier = [startId];
38	
39	  while (frontier.length > 0) {
40	    const next: string[] = [];
41	    for (const nodeId of frontier) {
42	      for (const neighbor of adj.get(nodeId) ?? []) {
43	        if (!visited.has(neighbor)) {
44	          visited.add(neighbor);
45	          next.push(neighbor);
46	        }
47	      }
48	    }
49	    if (next.length > 0) {
50	      layers.push(next);
51	      frontier = next;
52	    } else {
53	      break;
54	    }
55	  }
56	
57	  return layers;
58	}
59	
60	/**
61	 * Hook that manages evidence propagation animation state.
62	 * Performs BFS from an evidence node and staggers visual highlights per hop.
63	 */
64	export function useAnimationPropagation() {
65	  const [state, setState] = useState<AnimationState>({
66	    animatingNodes: new Set(),
67	    animatingEdges: new Set(),
68	    evidenceNodeId: null,
69	  });
70	
71	  // Ref to store timeout IDs for cancellation
72	  const timersRef = useRef<number[]>([]);
73	  const activeRef = useRef(false);
74	
75	  const cancelAnimation = useCallback(() => {
76	    activeRef.current = false;
77	    for (const t of timersRef.current) {
78	      window.clearTimeout(t);
79	    }
80	    timersRef.current = [];
81	    setState({
82	      animatingNodes: new Set(),
83	      animatingEdges: new Set(),
84	      evidenceNodeId: null,
85	    });
86	  }, []);
87	
88	  const triggerAnimation = useCallback(
89	    (evidenceNodeId: string, allEdges: GraphEdge[]) => {
90	      // Cancel any in-progress animation
91	      cancelAnimation();
92	      activeRef.current = true;
93	
94	      const layers = bfsLayers(evidenceNodeId, allEdges);
95	      const maxHops = layers.length;
96	      // Cap stagger so total doesn't exceed MAX_DURATION
97	      const stagger = Math.min(HOP_DELAY, Math.floor(MAX_DURATION / Math.max(maxHops, 1)));
98	
99	      const timers: number[] = [];
100	      const allNodes = new Set<string>();
101	      const allEdgeKeys = new Set<string>();
102	
103	      // Schedule each layer
104	      for (let hop = 0; hop < layers.length; hop++) {
105	        const delay = hop * stagger;
106	        const t = window.setTimeout(() => {
107	          if (!activeRef.current) return;
108	
109	          // Add this layer's nodes
110	          for (const nodeId of layers[hop]!) {
111	            allNodes.add(nodeId);
112	          }
113	
114	          // Add edges between this layer and previous layers
115	          if (hop > 0) {
116	            const prevNodes = new Set<string>();
117	            for (let p = 0; p < hop; p++) {
118	              for (const n of layers[p]!) prevNodes.add(n);
119	            }
120	            for (const nodeId of layers[hop]!) {
121	              for (const e of allEdges) {
122	                const src = e.source;
123	                const tgt = e.target;
124	                if (
125	                  (src === nodeId && prevNodes.has(tgt)) ||
126	                  (tgt === nodeId && prevNodes.has(src))
127	                ) {
128	                  allEdgeKeys.add(edgeKey(src, tgt));
129	                }
130	              }
131	            }
132	          }
133	
134	          setState({
135	            animatingNodes: new Set(allNodes),
136	            animatingEdges: new Set(allEdgeKeys),
137	            evidenceNodeId,
138	          });
139	        }, delay);
140	        timers.push(t);
141	      }
142	
143	      // Schedule cleanup after all layers + a hold duration
144	      const holdDuration = 600;
145	      const totalDuration = (layers.length - 1) * stagger + holdDuration;
146	      const cleanupTimer = window.setTimeout(() => {
147	        if (!activeRef.current) return;
148	        activeRef.current = false;
149	        setState({
150	          animatingNodes: new Set(),
151	          animatingEdges: new Set(),
152	          evidenceNodeId: null,
153	        });
154	      }, totalDuration);
155	      timers.push(cleanupTimer);
156	
157	      timersRef.current = timers;
158	    },
159	    [cancelAnimation],
160	  );
161	
162	  return {
163	    animatingNodes: state.animatingNodes,
164	    animatingEdges: state.animatingEdges,
165	    evidenceNodeId: state.evidenceNodeId,
166	    triggerAnimation,
167	    cancelAnimation,
168	  };
169	}
