1	import { createContext, useContext, useState, useCallback, type ReactNode } from "react";
2	
3	export interface Assumption {
4	  variableId: string;
5	  outcomeId: string;
6	  /** Display label for the assumption */
7	  label: string;
8	}
9	
10	interface AssumptionState {
11	  assumptions: Assumption[];
12	  addAssumption: (a: Assumption) => void;
13	  removeAssumption: (variableId: string) => void;
14	  clearAll: () => void;
15	  /** Restore a full set of assumptions (used by undo) */
16	  setAllAssumptions: (assumptions: Assumption[]) => void;
17	  hasAssumption: (variableId: string) => boolean;
18	  getAssumption: (variableId: string) => Assumption | undefined;
19	  /** Context array for API calls */
20	  contextPayload: Array<{ variableId: string; outcomeId: string }>;
21	}
22	
23	const AssumptionCtx = createContext<AssumptionState | null>(null);
24	
25	export function AssumptionProvider({ children }: { children: ReactNode }) {
26	  const [assumptions, setAssumptions] = useState<Assumption[]>([]);
27	
28	  const addAssumption = useCallback((a: Assumption) => {
29	    setAssumptions((prev) => {
30	      const filtered = prev.filter((p) => p.variableId !== a.variableId);
31	      return [...filtered, a];
32	    });
33	  }, []);
34	
35	  const removeAssumption = useCallback((variableId: string) => {
36	    setAssumptions((prev) => prev.filter((p) => p.variableId !== variableId));
37	  }, []);
38	
39	  const clearAll = useCallback(() => setAssumptions([]), []);
40	
41	  const setAllAssumptions = useCallback((all: Assumption[]) => setAssumptions(all), []);
42	
43	  const hasAssumption = useCallback(
44	    (variableId: string) => assumptions.some((a) => a.variableId === variableId),
45	    [assumptions],
46	  );
47	
48	  const getAssumption = useCallback(
49	    (variableId: string) => assumptions.find((a) => a.variableId === variableId),
50	    [assumptions],
51	  );
52	
53	  const contextPayload = assumptions.map((a) => ({
54	    variableId: a.variableId,
55	    outcomeId: a.outcomeId,
56	  }));
57	
58	  return (
59	    <AssumptionCtx.Provider
60	      value={{ assumptions, addAssumption, removeAssumption, clearAll, setAllAssumptions, hasAssumption, getAssumption, contextPayload }}
61	    >
62	      {children}
63	    </AssumptionCtx.Provider>
64	  );
65	}
66	
67	export function useAssumptions() {
68	  const ctx = useContext(AssumptionCtx);
69	  if (!ctx) throw new Error("useAssumptions must be used within AssumptionProvider");
70	  return ctx;
71	}
