1	import { useState, useCallback } from "react";
2	import { useOptionalHistory } from "./HistoryContext";
3	import { ProbabilityEditCommand, type DraftEdit } from "./commands";
4	
5	/**
6	 * Local draft buffer for probability edits with undo/redo support.
7	 *
8	 * Staged edits are stored locally. On undo/redo the draft map is updated.
9	 * The consumer calls `commit()` to submit all staged drafts to the server.
10	 */
11	export function useDraftEdits() {
12	  const history = useOptionalHistory();
13	
14	  // Map from "entryIndex::outcomeId" to drafted probability
15	  const [drafts, setDrafts] = useState<Map<string, DraftEdit>>(new Map());
16	
17	  const draftKey = (entryIndex: number, outcomeId: string) => `${entryIndex}::${outcomeId}`;
18	
19	  const applyDrafts = useCallback((edits: DraftEdit[]) => {
20	    setDrafts((prev) => {
21	      const next = new Map(prev);
22	      for (const edit of edits) {
23	        next.set(draftKey(edit.entryIndex, edit.outcomeId), edit);
24	      }
25	      return next;
26	    });
27	  }, []);
28	
29	  const revertDrafts = useCallback((edits: DraftEdit[]) => {
30	    setDrafts((prev) => {
31	      const next = new Map(prev);
32	      for (const edit of edits) {
33	        const key = draftKey(edit.entryIndex, edit.outcomeId);
34	        if (!edit.hadPriorDraft) {
35	          // No draft existed before this edit — remove it entirely
36	          next.delete(key);
37	        } else {
38	          // Restore to previous draft value
39	          next.set(key, { ...edit, probability: edit.previousProbability });
40	        }
41	      }
42	      return next;
43	    });
44	  }, []);
45	
46	  const stageDraft = useCallback(
47	    (edit: DraftEdit) => {
48	      // Look up existing draft to track previous value
49	      const key = draftKey(edit.entryIndex, edit.outcomeId);
50	      const existing = drafts.get(key);
51	      const hadPriorDraft = existing !== undefined;
52	      const previousProbability = existing?.probability ?? edit.previousProbability;
53	
54	      const draftWithPrev: DraftEdit = { ...edit, previousProbability, hadPriorDraft };
55	      const cmd = new ProbabilityEditCommand({
56	        drafts: [draftWithPrev],
57	        applyDrafts,
58	        revertDrafts,
59	      });
60	      cmd.execute();
61	      history?.push(cmd);
62	    },
63	    [drafts, history, applyDrafts, revertDrafts],
64	  );
65	
66	  const getDraft = useCallback(
67	    (entryIndex: number, outcomeId: string): number | undefined => {
68	      return drafts.get(draftKey(entryIndex, outcomeId))?.probability;
69	    },
70	    [drafts],
71	  );
72	
73	  const clearDrafts = useCallback(() => {
74	    setDrafts(new Map());
75	  }, []);
76	
77	  const hasDrafts = drafts.size > 0;
78	
79	  const allDrafts = useCallback(() => Array.from(drafts.values()), [drafts]);
80	
81	  return {
82	    stageDraft,
83	    getDraft,
84	    clearDrafts,
85	    hasDrafts,
86	    allDrafts,
87	    drafts,
88	  };
89	}
